+                package p.q;
+                /**
+                 * An interface.
+                 * {@warning [id=inline-TYPE-warning] inline warning}
+                 * @warning [id=block-TYPE-warning] block warning
+                 */
+                public interface I {
+                    /**
+                     * A method.
+                     * {@warning [id=inline-METHOD-warning] inline warning}
+                     * @warning [id=block-METHOD-warning] block warning
+                     */
+                    void m();
+                    /**
+                     * An enum.
+                     * {@warning [id=inline-TYPE-warning] inline warning}
+                     * @warning [id=block-TYPE-warning] block warning
+                     */
+                    enum E {
